function configuredApiBase(){ return String((state.session && state.session.api_base) || safeStorage.getItem('superidev2-api-base') || bootApiBase || '').trim().replace(/\/$/, ''); }
async function apiRequest(route, options={}){ const apiBase=configuredApiBase(); if(!apiBase) throw new Error('API base is not configured.'); const headers={ ...(options.headers||{}) }; if(state.session && state.session.auth_source==='server' && state.session.access_token && !headers.authorization) headers.authorization=`Bearer ${state.session.access_token}`; const response=await fetch(`${apiBase}${route}`, { ...options, headers }); const text=await response.text(); let data={ ok:false, error:'invalid-json' }; try{ data=JSON.parse(text); }catch{} if(response.status===401 && state.session && state.session.auth_source==='server' && state.session.refresh_token){ const refreshed=await refreshServerSession(); if(refreshed) return apiRequest(route, options); } if(!response.ok) throw new Error(data.error || `Request failed (${response.status}).`); return data; }
