  function buildPreview(){ assertTrustedSessionSync(); saveEditorBack(); const doc=state.projectMode==='skydocx' ? buildSkydocxPreview() : state.projectMode==='skyeblog' ? buildSkyeblogPreview() : buildCodePreview(); els.previewFrame.srcdoc=doc; els.buildStatus.textContent=`Preview built from ${Object.keys(state.files).length} files.`; els.previewStatus.textContent='Live'; updateSystemSummary(); writeLog(`[build] preview built :: run_id=${runId} :: mode=${state.projectMode}`); return doc; }
  function generateAuthorPackage(){ assertTrustedSessionSync(); saveEditorBack(); const metadata=parseJsonFile('metadata.json',{}); const edition=parseJsonFile('edition.json',{}); const storefront=parseJsonFile('storefront.json',{}); const manuscript=readText('manuscript.md') || readText('post.md'); const packageBody=canonicalize({ schema:'skye.skydocx.package', version:'3.2.0', run_id:runId, workspace_mode:state.projectMode, title:metadata.title || deriveWorkspaceTitleName(), slug:metadata.slug || slugify(metadata.title || deriveWorkspaceTitleName()), author:metadata.author || (state.session ? state.session.operator : 'Operator'), imprint:metadata.imprint || 'SOLEnterprises', edition:edition.editionName || 'Founding Release', edition_number:edition.editionNumber || '1.0.0', direct_sale:{ checkout_mode:storefront.checkoutMode || 'direct-first', price_usd:metadata.priceUsd || 0, membership_upsell:metadata.membershipUpsell || null, bundle_targets:storefront.bundleTargets || [] }, territories:metadata.territories || [], outputs:edition.outputs || ['docx-master','pdf-suite'], manuscript_excerpt:excerpt(manuscript), source_files:Object.keys(state.files).sort() }); state.publishingArtifacts.authorPackage=packageBody; els.packagePayload.value=JSON.stringify(packageBody,null,2); els.packageStatus.textContent=`Author package ready for ${packageBody.slug}.`; els.publishingSummary.textContent=`author_package=${packageBody.slug}\nedition=${packageBody.edition_number}\noutputs=${packageBody.outputs.join(', ')}\ndirect_sale_price=${packageBody.direct_sale.price_usd}`; updateSystemSummary(); writeLog(`[publishing] author package generated :: slug=${packageBody.slug}`); return packageBody; }
  function generateBlogPackage(){ assertTrustedSessionSync(); saveEditorBack(); const metadata=parseJsonFile('metadata.json',{}); const storefront=parseJsonFile('storefront.json',{}); const channel=parseJsonFile('channel.json',{}); const campaign=parseJsonFile('campaign.json',{}); const post=readText('post.md') || readText('manuscript.md'); const packageBody=canonicalize({ schema:'skye.skyeblog.package', version:'3.2.0', run_id:runId, workspace_mode:state.projectMode, headline:channel.channelTitle || metadata.title || deriveWorkspaceTitleName(), article_slug:channel.slug || metadata.slug || slugify(channel.channelTitle || metadata.title || deriveWorkspaceTitleName()), author:channel.author || metadata.author || (state.session ? state.session.operator : 'Operator'), release_hook:campaign.releaseHook || storefront.heroLine || 'Launch article seeded from canonical release', feed_entry:{ excerpt:excerpt(post), cta_label:channel.ctaLabel || 'Open release lane', canonical_collection:channel.canonicalCollection || metadata.slug || null }, promo_targets:campaign.promoTargets || [], callouts:campaign.callouts || [], source_files:Object.keys(state.files).sort() }); state.publishingArtifacts.blogPackage=packageBody; els.packagePayload.value=JSON.stringify(packageBody,null,2); els.packageStatus.textContent=`Blog package ready for ${packageBody.article_slug}.`; els.publishingSummary.textContent=`blog_package=${packageBody.article_slug}\npromo_targets=${packageBody.promo_targets.join(', ')}\ncallouts=${packageBody.callouts.join(', ')}`; updateSystemSummary(); writeLog(`[publishing] blog package generated :: slug=${packageBody.article_slug}`); return packageBody; }
  
async function createCheckoutSession(){ assertTrustedSessionSync(); saveEditorBack(); const authorPackage=state.publishingArtifacts.authorPackage || generateAuthorPackage(); const buyerName=`${(state.session && state.session.operator) || 'Reader'} Library Buyer`; const buyerEmail=`${slugify((state.session && state.session.operator) || 'reader')}@library.local`; if(state.session && state.session.auth_source==='server' && configuredApiBase()){ const response=await apiRequest('/api/payments/checkout/session', { method:'POST', headers:{ 'content-type':'application/json' }, body:JSON.stringify({ title:authorPackage.title, amount_usd:Number(authorPackage.direct_sale.price_usd || 0), customer_email:buyerEmail, metadata:{ slug:authorPackage.slug } }) }); state.commerce.checkoutSession=response.session; els.checkoutPayload.value=JSON.stringify(response, null, 2); els.checkoutStatus.textContent=`Server checkout session ready for ${response.session.session_id}.`; updateSystemSummary(); writeLog(`[commerce] server checkout ready :: session=${response.session.session_id}`); return response.session; } const body={ schema:'skye.directsale.checkout.session', version:'3.2.0', created_at:nowIso(), run_id:runId, session_id:`chk_${Date.now().toString(36)}`, release_slug:authorPackage.slug, title:authorPackage.title, buyer:{ name:buyerName, email:buyerEmail }, amount_usd:Number(authorPackage.direct_sale.price_usd || 0), checkout_mode:authorPackage.direct_sale.checkout_mode || 'direct-first', bundle_targets:authorPackage.direct_sale.bundle_targets || [], membership_upsell:authorPackage.direct_sale.membership_upsell || null, status:'ready' }; const session={ ...body, integrity_hash:stableHash(body) }; state.commerce.checkoutSession=session; els.checkoutPayload.value=JSON.stringify(session,null,2); els.checkoutStatus.textContent=`Checkout session ready for ${session.release_slug}.`; updateSystemSummary(); writeLog(`[commerce] checkout ready :: slug=${session.release_slug}`); return session; }
  async function completePurchase(){ assertTrustedSessionSync(); const session=state.commerce.checkoutSession || await createCheckoutSession(); if(state.session && state.session.auth_source==='server' && configuredApiBase()){ if(session.provider==='stripe' && session.provider_mode==='live') throw new Error('Live Stripe checkout must complete through the provider callback/webhook lane.'); const response=await apiRequest('/api/payments/checkout/complete-mock', { method:'POST', headers:{ 'content-type':'application/json' }, body:JSON.stringify({ session_id:session.session_id }) }); state.commerce.store=clone(response.commerce); renderCommerce(); els.checkoutPayload.value=JSON.stringify(response, null, 2); els.checkoutStatus.textContent=`Server purchase recorded for ${session.session_id}.`; updateSystemSummary(); writeLog(`[commerce] server purchase complete :: session=${session.session_id}`); return response; } const sessionLocal=session; const store=state.commerce.store || loadCommerceStore(); const purchasedAt=nowIso(); const previousLedgerHash=store.analytics?.latest_ledger_hash || null; const orderBody={ schema:'skye.directsale.order', version:'3.2.0', order_id:`ord_${Date.now().toString(36)}`, session_id:session.session_id, purchased_at:purchasedAt, buyer:session.buyer, release_slug:session.release_slug, title:session.title, amount_usd:session.amount_usd, status:'paid', previous_ledger_hash:previousLedgerHash }; const order={ ...orderBody, integrity_hash:stableHash(orderBody) }; const entitlementBody={ schema:'skye.directsale.entitlement', version:'3.2.0', entitlement_id:`ent_${Date.now().toString(36)}`, order_id:order.order_id, granted_at:purchasedAt, buyer_email:session.buyer.email, release_slug:session.release_slug, access:['epub','pdf','bonus-assets'] }; const entitlement={ ...entitlementBody, integrity_hash:stableHash(entitlementBody) }; const libraryBody={ schema:'skye.directsale.library.item', version:'3.2.0', library_id:`lib_${Date.now().toString(36)}`, order_id:order.order_id, entitlement_id:entitlement.entitlement_id, added_at:purchasedAt, buyer_email:session.buyer.email, release_slug:session.release_slug, title:session.title, download_formats:['epub','pdf'], update_channel:'owned-library' }; const libraryItem={ ...libraryBody, integrity_hash:stableHash(libraryBody), fulfillment_token:stableHash({ order_id:order.order_id, entitlement_id:entitlement.entitlement_id, library_id:libraryBody.library_id, buyer_email:libraryBody.buyer_email, release_slug:libraryBody.release_slug }) }; const ledgerHash=stableHash({ previousLedgerHash, order:{...orderBody, integrity_hash:order.integrity_hash}, entitlement, libraryItem:{...libraryBody, integrity_hash:libraryItem.integrity_hash, fulfillment_token:libraryItem.fulfillment_token} }); store.orders.push({ ...order, ledger_hash:ledgerHash }); store.entitlements.push(entitlement); store.library.push({ ...libraryItem, ledger_hash:ledgerHash }); store.updated_at=purchasedAt; store.analytics={ orders_count:store.orders.length, entitlements_count:store.entitlements.length, library_count:store.library.length, gross_usd:store.orders.reduce((sum,item)=>sum+Number(item.amount_usd||0),0), latest_ledger_hash:ledgerHash }; state.commerce.store=store; persistCommerceStore(); renderCommerce(); els.checkoutPayload.value=JSON.stringify({ session, order:{...order, ledger_hash:ledgerHash}, entitlement, library_item:{...libraryItem, ledger_hash:ledgerHash}, verification:verifyLocalCommerceStore(store) }, null, 2); els.checkoutStatus.textContent=`Purchase recorded for ${session.release_slug}.`; updateSystemSummary(); writeLog(`[commerce] purchase complete :: order=${order.order_id} :: library=${store.library.length}`); return { session, order, entitlement, libraryItem }; }
  async function refreshLibrary(){ assertTrustedSessionSync(); if(state.session && state.session.auth_source==='server' && configuredApiBase()){ const response=await apiRequest('/api/runtime/commerce', { method:'GET' }); state.commerce.store=clone(response.commerce); renderCommerce(); updateSystemSummary(); writeLog('[commerce] server library refreshed'); return response.summary; } renderCommerce(); updateSystemSummary(); writeLog('[commerce] library refreshed'); return summarizeCommerce(); }
  async function exportWorkspace(){ assertTrustedSessionSync(); saveEditorBack(); const passphrase=els.operatorPassphrase.value; if(passphrase.length<12) throw new Error('Export blocked because passphrase is too short.'); const unsigned=buildUnsignedBundle(); const signature=await signBrowserPayload(unsigned, passphrase); const bundle={ ...unsigned, signature }; const serialized=JSON.stringify(bundle,null,2); els.exportPayload.value=serialized; els.importPayload.value = els.importPayload.value || serialized; els.exportStatus.textContent=`Export ready (${serialized.length} bytes).`; updateSystemSummary(); writeLog(`[export] workspace exported :: bytes=${serialized.length} :: mode=${state.projectMode}`); return bundle; }
