function runPublishingSmoke(){ assertTrustedSessionSync(); saveEditorBack(); if(!state.catalog.active_title_id){ els.catalogTitleName.value=els.catalogTitleName.value.trim() || deriveWorkspaceTitleName(); saveTitleToCatalog(false); } const authorPackage=state.publishingArtifacts.authorPackage || generateAuthorPackage(); const blogPackage=state.publishingArtifacts.blogPackage || generateBlogPackage(); const report={ run_id:runId, timestamp:nowIso(), workspace_mode:state.projectMode, active_title_id:state.catalog.active_title_id, active_title_name:state.catalog.analytics.active_title_name, has_preview:els.previewStatus.textContent==='Live', has_author_package:authorPackage.schema==='skye.skydocx.package', has_blog_package:blogPackage.schema==='skye.skyeblog.package', required_files_present: state.projectMode==='skydocx' ? ['manuscript.md','metadata.json','edition.json','storefront.json'].every((name)=>!!state.files[name]) : state.projectMode==='skyeblog' ? ['post.md','channel.json','campaign.json','cta.html'].every((name)=>!!state.files[name]) : ['index.html','styles.css','app.js'].every((name)=>!!state.files[name]), has_checkout_session:!!state.commerce.checkoutSession, has_library_access:(state.commerce.store && state.commerce.store.library.length>0) || false, catalog_titles:state.catalog.analytics.titles_count, release_runs_before_record:state.releaseHistory ? state.releaseHistory.analytics.runs_count : 0, package_payload_bytes:els.packagePayload.value.length, export_payload_bytes:els.exportPayload.value.length, ok:false };
    report.ok=report.has_preview && report.has_author_package && report.has_blog_package && report.required_files_present && report.has_checkout_session && report.has_library_access && report.catalog_titles>0; state.publishingArtifacts.publishingSmoke=report; recordPublishingRun(report); els.publishingSummary.textContent=JSON.stringify({ ...report, release_runs_after_record:state.releaseHistory.analytics.runs_count }, null, 2); els.publishingStatus.textContent=report.ok ? `Publishing smoke complete for ${runId}.` : `Publishing smoke failed for ${runId}.`; updateSystemSummary(); writeLog(`[publishing-smoke] ${report.ok ? 'PASS' : 'FAIL'} :: mode=${state.projectMode}`); return report; }
  function runDiagnostics(){ const controls=[...document.querySelectorAll('[data-smoke-control]')].map((node)=>node.dataset.smokeControl); const commerceVerification=verifyLocalCommerceStore(state.commerce.store || emptyCommerceState()); const report={ run_id:runId, timestamp:nowIso(), auth_valid:sessionValid(state.session), auth_source:state.session ? state.session.auth_source : null, api_base:configuredApiBase() || null, controls, build_live:els.previewStatus.textContent==='Live', export_present:!!els.exportPayload.value, import_present:!!els.importPayload.value, package_present:!!els.packagePayload.value, checkout_present:!!els.checkoutPayload.value, file_count:Object.keys(state.files).length, gateway_mode:state.secureDefaults.gatewayMode, workspace_mode:state.projectMode, orders_count:state.commerce.store ? state.commerce.store.orders.length : 0, library_count:state.commerce.store ? state.commerce.store.library.length : 0, catalog_titles:state.catalog ? state.catalog.titles.length : 0, release_runs:state.releaseHistory ? state.releaseHistory.runs.length : 0, ledger_ok:commerceVerification.ok, truth_boundary:getTruthBoundary() }; writeLog(`[diagnostics] ${JSON.stringify(report)}`); els.smokeStatus.textContent=`Diagnostics complete for ${runId}.`; updateSystemSummary(); return report; }
