  async function resetSession(){ if(state.session && state.session.auth_source==='server' && configuredApiBase()){ try{ await fetch(`${configuredApiBase()}/api/auth/logout`, { method:'POST', headers:{ 'content-type':'application/json', authorization:`Bearer ${state.session.access_token}` }, body:JSON.stringify({ refresh_token:state.session.refresh_token }) }); }catch{} } safeStorage.removeItem('superidev2-session'); state.session=null; renderSession(); updateSystemSummary(); writeLog('[auth] session reset'); }
