  els.resetBtn.addEventListener('click', resetSession);
  els.loadDemoBtn.addEventListener('click',()=>runGuarded(()=>loadPreset('code')));
  els.loadSkydocxBtn.addEventListener('click',()=>runGuarded(()=>loadPreset('skydocx')));
